// CodePrint.jsx
import React, { useState } from 'react';
import Barcode from 'react-barcode';
import { BiPrinter } from 'react-icons/bi';
import { useParams } from 'react-router-dom';
import c from './codeprint.module.scss';   // стили-модуль

const CodePrint = () => {
  const { code, name, price } = useParams();   // /:code/:name/:price в роуте
  const [qty, setQty] = useState(1);

  const labels = Array.from({ length: qty });

  return (
    <div className={c.wrapper}>
      {labels.map((_, i) => (
        <div key={i} className={c.label}>
          <h3>{name}</h3>
          <p>{price} сом</p>

          {/* рендерим как canvas, так XPrinter печатает без проблем */}
          <Barcode
            value={code}
            renderer="canvas"
            format="CODE128"
            width={2}
            height={30}
            margin={0}
            displayValue={false}
            className={c.barcode}
          />
        </div>
      ))}

      {/* панель управления (не печатается, см. @media print) */}
      <div className={c.controls}>
        <input
          type="number"
          min="1"
          value={qty}
          onChange={e => setQty(Math.max(+e.target.value, 1))}
        />
        <button onClick={() => window.print()}>
          Печать&nbsp;<BiPrinter />
        </button>
      </div>
    </div>
  );
};

export default CodePrint;
